class Solution {
public:
    int primePalindrome(int n) {
        while (true) {
            if (isPrime(n) && isPalindrome(n)) {
                return n;
            }
            n++;
        }
    }

    bool isPrime(int num) {
        if (num < 2) return false;
        for (int i = 2; i * i <= num; i++) {
            if (num % i == 0) return false;
        }
        return true;
    }

    bool isPalindrome(int num) {
        int rev = 0;
        int original = num;
        while (num != 0) {
            rev = rev * 10 + num % 10;
            num /= 10;
        }
        return original == rev;
    }
};
```

